"""
MKT Christ Commentary — Job chapters 30–32
Run: python3 scripts/zc-christ-job-30-32.py

Source data used:
- data/interlinear/job.json
- data/translation/draft/mediating/job.json

Key decisions in this range:
- Ch30: Job's social humiliation (30:9-10) and divine silence (30:20) closely parallel
  the Passion — the mockers, the spitting, the unanswered cry. These are type/shadow.
- Ch31: Job's oath of innocence across 12 moral domains is the clearest OT portrait of
  a blameless life. Each domain finds its fulfillment in Christ (who alone passes the oath)
  or in the gospel's reversal (substitution for the guilty).
- Ch32: Elihu's introduction — his appeal to the Spirit/breath (32:8), refusal of flattery
  (32:21-22), and prophetic compulsion (32:18-19) point toward the Spirit-filled witness
  the NT describes. God does not rebuke Elihu in the epilogue.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOB = {
  "30": {
    "1": "<p>A shadow: Job's social inversion — those of lower social standing now mock the man of honor. The NT's deepest statement of this pattern is the Passion: the Son of God is mocked by soldiers, bystanders, and crucified criminals (Matt 27:29-44). The honor-reversal Job experiences is the structural shape of Christ's humiliation; the resurrection is the re-inversion.</p>",
    "2": "<p>A theme: the dismissal of the useless — those whose vitality has perished. The NT's transformation is the inclusion of the weak: 'God chose what is weak in the world to shame the strong' (1 Cor 1:27). The very people whom the world has written off as past their vigor are the subjects of God's particular attention.</p>",
    "3": "<p>A theme: want and famine — the outcasts who survive on the margins. The NT's beatitude addresses this: 'Blessed are those who hunger and thirst for righteousness, for they shall be satisfied' (Matt 5:6). The ones driven to barren places by deprivation are the same ones Christ declares blessed.</p>",
    "4": "<p>A theme: saltbush and broom root — the desperate diet of the marginalized. The NT shows Christ eating with the outcast (Luke 15:2), feeding the hungry in desolate places (Mark 6:30-44), and being sustained by his father's will 'as food' (John 4:34). The desolate place is where Christ regularly appears.</p>",
    "5": "<p>A revelation of God: driven out from society, shouted after like thieves — the social death of the ostracized. Christ himself was 'despised and rejected by men' (Isa 53:3) and crucified outside the city gate (Heb 13:12-13). The letter to the Hebrews draws this out as the pattern for disciples: 'let us go to him outside the camp, bearing the reproach he endured.'</p>",
    "6": "<p>A theme: living in gullies, holes, and rocks — the dispossessed dwelling in the earth's margins. The NT's parallel: 'foxes have holes and birds of the air have nests, but the Son of Man has nowhere to lay his head' (Matt 8:20). The one who made the earth had no fixed home in it.</p>",
    "7": "<p>A theme: crying out among the bushes — the inarticulate lament of the destitute. The NT holds that the Spirit intercedes for us 'with groanings too deep for words' (Rom 8:26) — the Spirit takes up the voiceless cry of the suffering and brings it before God. The cry beneath the nettles is heard.</p>",
    "8": "<p>A theme: 'children of fools, children of men without a name' — those who carry no honorable lineage. The NT's reversal: 'to all who did receive him, who believed in his name, he gave the right to become children of God' (John 1:12). The nameless are given the name; those without lineage are adopted into the family of God.</p>",
    "9": "<p>A type: 'I have become their song and their byword' — the mocked one whose name is a taunt. Psalm 69:12, which the NT applies to Christ (John 15:25, Rom 15:3), says the same: 'those who sit in the gate talk about me, and the drunkards make songs about me.' Job's becoming the occasion of mockery is the same pattern the NT sees fulfilled in Christ's passion.</p>",
    "10": "<p>A type: 'they despise me and keep their distance; they do not hesitate to spit in my face' — the full sequence of social rejection and physical contempt. The NT fulfillment is explicit: the soldiers 'spit on him' (Matt 27:30); he was 'despised and rejected' (Isa 53:3). Job's suffering here carries the structural shape of the Passion's humiliation sequence.</p>",
    "11": "<p>A revelation of God: 'God has loosed my cord and afflicted me' — Job attributes his social collapse to divine action. The NT's parallel is the Passion: 'this Jesus, delivered up according to the definite plan and foreknowledge of God, you crucified and killed by the hands of lawless men' (Acts 2:23). Divine intent and human wickedness operate simultaneously in both cases.</p>",
    "12": "<p>A shadow: 'the mob rises up; they push aside my feet and build their roads of ruin against me' — the organized assault of enemies. The NT's image of the crowd pressing against Christ and the systematic legal apparatus that condemned him has this same character of organized, coordinated assault.</p>",
    "13": "<p>A shadow: 'they need no one to help them' — the self-sustaining momentum of hostility against the righteous. The opposition to Christ is similarly depicted as needing no external motivation: the chief priests, Pilate, the crowd each act from their own interests, yet together they accomplish what the NT calls the Father's eternal purpose (Acts 4:27-28).</p>",
    "14": "<p>A shadow: 'they rush in amid the ruin' — enemies pouring through the breach like floodwater. The Passion has this quality: once the arrest began, the cascade of betrayal, denial, trial, and crucifixion followed with a logic that no human power arrested. The disciples fled; the crowd demanded death.</p>",
    "15": "<p>A shadow: 'terrors are unleashed against me; my dignity is driven away like the wind, my prosperity like a cloud' — the stripping of all exterior honor. The NT's Passion strips Christ of every dignity: garments divided, crown of thorns, the charge of blasphemy, death between criminals. What Job describes as social and economic stripping, Christ undergoes completely.</p>",
    "16": "<p>A shadow: 'my soul is poured out within me' — the language of total interior depletion. Isaiah 53:12 uses the same 'pour out' language of Christ: 'he poured out his soul to death.' The interior desolation Job describes — not just physical but the inner pouring out of self — is the pattern the Servant's death embodies completely.</p>",
    "17": "<p>A revelation of God: 'my bones are racked with pain, and the pain that gnaws at me never rests' — the unrelenting physical suffering. The NT identifies Christ as the one 'acquainted with grief' (Isa 53:3) and who 'suffered in the flesh' (1 Pet 4:1). The incarnation means God knows what it is to have bones that ache.</p>",
    "18": "<p>A shadow: 'with great force my clothing is seized by my disease; it binds me at the neck' — disease that grasps and restricts. At the crucifixion, Christ's garments are taken from him by force (Matt 27:35) — the reversal of clothing as bondage into clothing as plunder.</p>",
    "19": "<p>A type: 'he has thrown me into the mud; I have become like dust and ashes' — total reduction to the earth from which humanity was made (Gen 2:7). The NT's descent language applies this to Christ: 'he was buried' (1 Cor 15:4) — returned to the earth before being raised from it. Job's mud is the grave's anticipation.</p>",
    "20": "<p>A type: 'I cry to you but you do not answer; I stand, and you only stare at me' — the unanswered cry to God. The direct NT parallel is Psalm 22:2 ('I cry by day, but you do not answer'), which Matthew 27:46 applies to the crucifixion. Job's experience of divine silence is the paradigmatic expression of the Passion's most terrifying moment.</p>",
    "21": "<p>A shadow: 'you have become cruel to me; with the power of your hand you oppose me' — God as the apparent adversary. At the cross, God 'did not spare his own Son but gave him up for us all' (Rom 8:32) — the divine hand that opposed the Son did so on behalf of those who deserve opposition. The apparent cruelty is the mechanism of the deepest love.</p>",
    "22": "<p>A revelation of God: 'you lift me up on the wind; you cause me to ride it and dissolve my substance' — being borne away by divine power toward dissolution. The NT speaks of Christ being 'lifted up' (John 3:14, 12:32) — the crucifixion and the ascension both use this language. The lifting that Job experiences as being dissolved, Christ transforms into the lifting that draws all people to himself.</p>",
    "23": "<p>A shadow: 'I know you will bring me to death, to the house appointed for all the living' — the certainty of death. Christ goes to the same house: he 'tasted death for everyone' (Heb 2:9), entering the house appointed for all the living so that those in him might exit it by resurrection. The certainty Job accepts becomes the certainty Christ transforms.</p>",
    "24": "<p>A revelation of God: 'does not one in a heap of ruins reach out his hand? does one not cry out in his disaster?' — the natural reflex of the suffering to call for help. The NT's response is that God has provided exactly this: 'for everyone who calls on the name of the Lord will be saved' (Rom 10:13). The cry from the heap of ruins is the prayer God answers.</p>",
    "25": "<p>A revelation of God: 'did I not weep for those in trouble? was not my soul grieved for the poor?' — Job's compassionate identification with the suffering. The NT reveals this as the divine character embodied in Christ: 'Jesus wept' (John 11:35) over Lazarus; he had 'compassion on them' (Matt 9:36) for the crowds. The empathy Job describes is the empathy of the incarnate God.</p>",
    "26": "<p>A revelation of God: 'when I looked for good, evil came; when I waited for light, darkness came' — the reversal of expectation in suffering. The disciples experienced this at Golgotha: they waited for the kingdom and got a cross. Easter is the reversal: the darkness of Friday becomes the light of Sunday, the evil absorbed becomes the good released.</p>",
    "27": "<p>A theme: 'my inner parts churn and do not rest' — the churning of unresolved suffering. The NT holds that present suffering produces endurance (Rom 5:3-4), not because the churning ceases but because it is working toward something. The restlessness is purposeful.</p>",
    "28": "<p>A shadow: 'I walk in mourning without the sun; I stand up in the assembly and cry out' — public mourning without light. The NT parallel: at the crucifixion, 'from the sixth hour there was darkness over all the land until the ninth hour' (Matt 27:45), and Christ cries out from within it. The assembly's response to the righteous sufferer is silence or mockery; God's response is resurrection.</p>",
    "29": "<p>A shadow: 'I have become a brother to jackals and a companion to wild birds' — identification with wild creatures of desolation. The NT places Christ in similar wilderness company: 'he was in the wilderness forty days... and he was with the wild animals' (Mark 1:13). The tamed world that should receive the righteous has expelled them to the wild margins.</p>",
    "30": "<p>A revelation of God: 'my skin has turned black; my bones burn with fever' — the physical signs of disease and dying. The incarnation is the Word taking on exactly this burning, blackening, mortal flesh. 'He himself bore our griefs and carried our sorrows' (Isa 53:4) — the specific physiology of suffering is what God bore in the Son.</p>",
    "31": "<p>A shadow: 'my harp has been turned to mourning and my flute to the sound of weeping' — the transformation of musical joy into lament. The NT holds that this mourning has an eschatological reversal: 'you will be sorrowful, but your sorrow will turn into joy' (John 16:20). The harp restored is the NT's image of the new creation's worship (Rev 5:8, 14:2).</p>"
  },
  "31": {
    "1": "<p>A shadow: 'I made a covenant with my eyes; how then could I look upon a young woman?' — sexual purity as covenantal integrity. Christ radicalized this: 'everyone who looks at a woman with lustful intent has already committed adultery with her in his heart' (Matt 5:28). Job's covenant-with-eyes is the OT form of the heart-purity Christ requires and himself perfectly embodies.</p>",
    "2": "<p>A revelation of God: the 'portion God assigns from above' — the divine allocation of fate and reward. The NT grounds this in Christ: 'in him we have obtained an inheritance' (Eph 1:11), determined by divine purpose. The portion that comes 'from above' is secured through the one who himself came 'from above' (John 3:31).</p>",
    "3": "<p>A revelation of God: 'is there not ruin for the unrighteous?' — the retribution principle that underlies Job's oath. The NT confirms the principle while transforming its application: the ruin deserved by the unrighteous fell on Christ, 'the righteous for the unrighteous, that he might bring us to God' (1 Pet 3:18). The principle stands; the one who bore it is unexpected.</p>",
    "4": "<p>A revelation of God: 'does he not see my ways and number all my steps?' — the divine omniscience as the ground of Job's oath. The NT confirms and personalizes this: 'even the hairs of your head are all numbered' (Matt 10:30). The same all-seeing God before whom Job stands is the Father who knows every detail of our lives.</p>",
    "5": "<p>A theme: 'if I have walked in falsehood, or my foot has rushed toward deceit' — the moral audit of one's path. Christ is 'the way' (John 14:6) — not just the destination but the pattern of walking. The one who invites disciples to walk in his way is himself the one who never rushed toward deceit.</p>",
    "6": "<p>A theme: 'let me be weighed in an honest balance, so that God may know my integrity' — the appeal to divine assessment. The NT's most searching passage on divine assessment is 2 Cor 5:10: 'we must all appear before the judgment seat of Christ.' But those in Christ appear wearing his righteousness, not their own — the balance is honest, and the one who stands in their place has already been weighed.</p>",
    "7": "<p>A theme: 'if my heart has followed my eyes, or any stain has clung to my hand' — the moral contamination that spreads from sight to heart to deed. The NT's diagnosis is the same: 'out of the heart come evil thoughts, murder, adultery...' (Matt 15:19). The sequence Job fears — sight corrupting heart corrupting action — is the sequence the gospel addresses at its root, by transforming the heart.</p>",
    "8": "<p>A theme: 'let me plant and another harvest' — the imprecation of displacement. The NT's positive form: 'one sows and another reaps' (John 4:37) describes the missionary pattern where labor benefits those who did not labor. The displacement Job invokes as curse becomes, in the gospel's economy, a description of the generous overflow of blessing.</p>",
    "9": "<p>A theme: the prohibition against adultery — 'if my heart has been drawn away by a woman.' Job's oath of marital fidelity is the OT foundation of the NT's teaching on covenant marriage (Matt 19:4-6, Eph 5:25-33). Christ's faithfulness to his bride, the church, is the theological grounding of the marital covenant Job here affirms.</p>",
    "10": "<p>A shadow: 'let my wife grind for another man' — the self-imprecation of maximum social shame. The NT transforms the marriage metaphor: Christ's relationship to the church is that of the faithful husband (Eph 5:25-27), who 'loved the church and gave himself up for her.' The shame Job invokes for infidelity is the mirror-image of the faithfulness Christ embodies.</p>",
    "11": "<p>A revelation of God: 'for that would be a shameful outrage and an iniquity deserving judgment' — the naming of sexual sin as a breach of justice, not merely decorum. The NT confirms this: 'flee from sexual immorality' is the command, grounded in the theology of the body as the temple of the Holy Spirit (1 Cor 6:18-20). The body belongs to God, which is why its violation is an iniquity.</p>",
    "12": "<p>A shadow: 'a fire that burns all the way to Abaddon' — the consequence of lust reaching into the realm of destruction. The NT's warning is parallel: 'if your right eye causes you to sin, tear it out and throw it away. For it is better that you lose one of your members than that your whole body be thrown into hell' (Matt 5:29). The fire that reaches Abaddon is the same fire Christ warns against.</p>",
    "13": "<p>A revelation of God: 'if I have dismissed the complaint of my servant or maidservant when they had a dispute with me' — the obligation of justice to those under one's authority. The NT grounds this in the incarnation: God himself took the form of a servant (Phil 2:7), making every servant's complaint a matter of divine concern. The master who dismisses a servant's case dismisses it before the one who became a servant.</p>",
    "14": "<p>A revelation of God: 'what could I do when God rises up? when he holds inquiry, what shall I answer him?' — the anticipation of divine scrutiny. The NT's comfort: those in Christ 'will not come into judgment' (John 5:24) — the inquiry that Job fears as exposing potential failure has already been conducted, and the verdict rendered: no condemnation (Rom 8:1).</p>",
    "15": "<p>A revelation of God: 'did not the one who made me in the womb make him too? did not one God form us both?' — the common humanity of master and servant, grounded in common creation. The NT's fullest expression: 'there is neither slave nor free... for you are all one in Christ Jesus' (Gal 3:28). The equality Job asserts creatorially, Paul grounds in the new creation inaugurated by Christ.</p>",
    "16": "<p>A revelation of God: 'if I have refused the poor what they needed, or caused the widow's eyes to fail' — the obligation to the poor and widow. The NT names care for the poor and orphan as 'religion that is pure and undefiled' (Jas 1:27). Christ's own ministry was characterized by concern for the poor (Luke 4:18); his body continues it.</p>",
    "17": "<p>A revelation of God: 'if I ate my food alone and the fatherless ate nothing' — the obligation to share one's table. The NT's eucharistic community is defined by this sharing: the early church had 'all things in common... distributing to each as any had need' (Acts 2:44-45). The closed table Job swears against is the antithesis of Christ's open one.</p>",
    "18": "<p>A revelation of God: 'from my youth the fatherless grew up with me as with a father' — a lifetime of care for the vulnerable. The NT names God as 'Father of the fatherless' (Ps 68:5) and grounds adoption into his family in Christ's work (Rom 8:15). Job's fatherly care for the fatherless mirrors the divine fatherhood that the gospel makes accessible.</p>",
    "19": "<p>A theme: 'if I have seen anyone dying from lack of clothing' — the obligation to clothe the naked. The NT's judgment scene turns on exactly this: 'I was naked and you clothed me... as you did it to one of the least of these my brothers, you did it to me' (Matt 25:36,40). The naked stranger is Christ; Job's oath is the life Christ commends at the judgment.</p>",
    "20": "<p>A revelation of God: 'if the wool of my sheep has not kept him warm' — care that comes from one's own resources. The NT's good shepherd 'lays down his life for the sheep' (John 10:11) — giving not just wool but himself. Job's generous self-giving from his own resources is the creaturely form of the divine self-giving in Christ.</p>",
    "21": "<p>A shadow: 'if I have raised my hand against the fatherless when I had allies at the city gate' — the abuse of power against the defenseless. The NT's condemnation of power used against the vulnerable is sharp (Luke 20:47: scribes who 'devour widows' houses'). Christ, who had all power, used it entirely on behalf of the defenseless.</p>",
    "22": "<p>A shadow: 'let my arm fall from its socket and be broken from the elbow' — the self-imprecation against arm-violence. The NT's parallel: Christ stretched out his arms on the cross — not to strike but to bear. The arms that Job swears will be broken if used unjustly were, in Christ, stretched out in the ultimate act of non-retaliatory self-giving.</p>",
    "23": "<p>A revelation of God: 'for the destruction God sends is a terror to me; before his majesty I cannot hold my ground' — the divine majesty as the ground of Job's ethical restraint. The NT's basis for ethics is the same: 'since we know the fear of the Lord, we persuade others' (2 Cor 5:11). The awe that motivates Job's integrity is taken up into the NT's theology of the divine majesty revealed in Christ.</p>",
    "24": "<p>A theme: 'if I have made gold my hope or called pure gold my security' — the prohibition of wealth as ultimate trust. The NT's parallel: 'you cannot serve God and money' (Matt 6:24); 'it is easier for a camel to go through the eye of a needle than for a rich person to enter the kingdom of God' (Matt 19:24). Job's oath against making gold his security is the OT form of Christ's teaching on mammon.</p>",
    "25": "<p>A theme: 'if I rejoiced that my wealth was great or that my hand had gained much' — the spiritual danger of satisfaction in abundance. The NT's beatitude is the reversal: 'blessed are the poor in spirit, for theirs is the kingdom of heaven' (Matt 5:3). The one who does not rejoice in his own hand's gain can receive the kingdom as gift.</p>",
    "26": "<p>A theme: 'if I gazed at the sun in its brilliance or the moon as it moved in splendor' — the prohibition of star and sun worship. The NT places Christ above all cosmic objects: he is 'the bright morning star' (Rev 22:16), and in the new creation 'the city has no need of sun or moon to shine on it, for the glory of God gives it light, and its lamp is the Lamb' (Rev 21:23). The objects of potential idolatry are subordinate to the one the gospel reveals.</p>",
    "27": "<p>A theme: 'my heart was secretly seduced, and my hand was kissed toward them' — the inner movement toward idolatry, the heart drawn away before the hand acts. The NT locates idolatry in the heart: 'covetousness... is idolatry' (Col 3:5). The secret seduction of the heart toward anything other than God is the root of idolatry that the gospel addresses by redirecting the heart's affection toward Christ.</p>",
    "28": "<p>A revelation of God: 'for I would have denied the God above' — the equation of cosmic idolatry with the denial of the true God. The NT's confession is the positive form: 'Jesus is Lord' (Rom 10:9) — the confession that the world's objects of idolatry (wealth, power, cosmic forces) do not hold final allegiance. To confess Christ is to deny the idols.</p>",
    "29": "<p>A revelation of God: 'if I rejoiced when my enemy was ruined or exulted when disaster found him' — the prohibition of schadenfreude. The NT's command is the positive version: 'love your enemies and pray for those who persecute you' (Matt 5:44). Christ prays from the cross for those who are executing him (Luke 23:34). Job's oath against enemy-joy is the minimum; Christ's active love for enemies is the fulfillment.</p>",
    "30": "<p>A revelation of God: 'I have not let my mouth sin by calling down a curse on his life' — the restrained tongue that does not curse enemies. The NT's positive: 'bless those who curse you, pray for those who abuse you' (Luke 6:28). Christ himself is the example: 'when he was reviled, he did not revile in return; when he suffered, he did not threaten' (1 Pet 2:23). Job's non-cursing is the threshold; Christ's active blessing is the fulfillment.</p>",
    "31": "<p>A revelation of God: 'who has not been filled with his food?' — the testimony of household generosity, confirmed by Job's own servants. The feeding motif is central to Christ's ministry: the miraculous feedings (Mark 6:42: 'they all ate and were satisfied'), the parables of banquets, the eucharist. The question 'who has not been filled?' is answered by those who ate with Jesus.</p>",
    "32": "<p>A revelation of God: 'no stranger had to sleep in the street; I opened my doors to the traveler' — radical hospitality. The NT's extension: 'do not neglect to show hospitality to strangers, for thereby some have entertained angels unawares' (Heb 13:2). Christ himself was 'a stranger' — 'he came to his own, and his own people did not receive him' (John 1:11) — but those who receive him receive the Father (Matt 10:40).</p>",
    "33": "<p>A type: 'if I have hidden my transgressions like Adam, concealing my iniquity in my heart' — the Adamic pattern of concealment after sin. Genesis 3:8-10 is the prototype: Adam hides from God after the fall. Christ is the second Adam (Rom 5:14-15) who does not hide but fully discloses himself: 'I am the way and the truth and the life' (John 14:6). Concealment is the Adamic response; transparent self-giving is the Christic reversal.</p>",
    "34": "<p>A revelation of God: 'because I feared the crowd and the contempt of families terrified me, so I kept silent' — the capitulation to social pressure that Job swears he has avoided. The NT's opposite is the martyr-witness: 'do not fear those who kill the body' (Matt 10:28). Christ before Pilate does not keep silent to preserve himself; he speaks truth to power (John 18:36-37). The fear Job overcame in his integrity, Christ overcame in his Passion.</p>",
    "35": "<p>A type: 'O that someone would hear me! here is my signature — let the Almighty answer me!' — the legal demand for a divine response. The divine speeches in chapters 38-41 answer this demand, though not in the way Job expected. In the NT, the ultimate divine answer to humanity's legal demand is the cross: God speaks in the death and resurrection of his Son. The signature Job produces is answered by the one who bears scars in hands and side (John 20:27).</p>",
    "36": "<p>A shadow: 'I would carry it on my shoulder and wear it as a crown on my head' — the paradox of bearing one's indictment as a mark of honor. The NT's parallel: the crown of thorns (John 19:2) placed mockingly on Christ's head becomes, in the resurrection's light, the sign of his true kingship. What is given in contempt is transformed into honor.</p>",
    "37": "<p>A shadow: 'I would approach him like a prince' — the confidence of approaching God as one entitled to his audience. The NT's language for the believer's access to God: 'with confidence draw near to the throne of grace' (Heb 4:16), not as a suppliant begging for attention but as those who have a right of access through Christ. Job's princely confidence is available to those who come through the one who is himself the Prince of Peace (Isa 9:6).</p>",
    "38": "<p>A theme: 'if my land has cried out against me and its furrows have wept' — the land bearing witness to its owner's conduct. The NT holds that creation itself testifies (Rom 1:20) and groans (Rom 8:22); the land's witness is real. The creation that cries out against those who abuse it waits for 'the revealing of the sons of God' (Rom 8:19) — the restoration Christ will bring.</p>",
    "39": "<p>A revelation of God: 'if I have eaten its produce without paying, or stripped the life from its owners' — the economic obligation of just dealing. The NT's equivalent: Zacchaeus, transformed by Jesus, restores fourfold what he has taken (Luke 19:8). The justice of honest economic dealing is what the encounter with Christ produces, not merely commands.</p>",
    "40": "<p>A theme: 'then let thistles grow instead of wheat, and weeds instead of barley' — the curse of the ground as the consequence of injustice. Genesis 3:17-18 is the background: thorns and thistles are the curse-sign of the fall. The NT holds that Christ 'redeemed us from the curse of the law by becoming a curse for us' (Gal 3:13) — he wore the thorns as his crown. The words of Job are ended at this verse, in a fitting image of what Christ absorbed.</p>"
  },
  "32": {
    "1": "<p>A theme: 'so these three men stopped answering Job, because he was righteous in his own eyes' — the paralysis of conventional wisdom before an anomalous case. The three friends could not answer because their theology lacked the categories for innocent suffering. The NT supplies the missing category: the suffering of the righteous is redemptive, not merely disciplinary, when joined to Christ's.</p>",
    "2": "<p>A theme: Elihu's anger 'burned against Job, because he declared himself righteous rather than God' — the accusation that Job's insistence on his own righteousness displaces God's. The NT navigates this tension: the doctrine of justification holds that the sinner is declared righteous not by his own insistence but by God's declaration through Christ. Job's self-defense, vindicated in 42:7, is not self-righteousness — it is honest assessment of his actual integrity.</p>",
    "3": "<p>A revelation of God: Elihu 'was also angry with the three friends because they had found no answer and yet had condemned Job' — he perceives the injustice of condemnation without proof. The NT's standard: 'judge not by appearances, but judge with right judgment' (John 7:24). The friends condemned without evidence; Elihu at least recognizes that evidence has not been produced.</p>",
    "4": "<p>A theme: Elihu 'had waited to speak... because the others were older than he' — deference to age as a wisdom convention. The NT both honors and qualifies this: 'do not let anyone despise you for your youth' (1 Tim 4:12); 'out of the mouth of infants and nursing babies you have prepared praise' (Matt 21:16). Wisdom is not the exclusive possession of the aged.</p>",
    "5": "<p>A theme: 'when Elihu saw that the three men had no answer, his anger was aroused' — the recognition that the conventional wisdom tradition has exhausted itself. The NT describes a similar moment: the religious leaders, questioned by Jesus about the baptism of John, 'knew not what to answer' (Mark 11:33). When conventional frameworks fail to answer, a new word is needed.</p>",
    "6": "<p>A theme: 'I am young and you are old; that is why I was afraid and held back' — the fear of speaking out of proper order. The NT's prophetic pattern overrides social hierarchy when the Spirit impels: 'when they arrest you and deliver you over, do not be anxious beforehand what you are to say, but say whatever is given you in that hour' (Mark 13:11). The Spirit speaks through those who defer, when deference reaches its limit.</p>",
    "7": "<p>A theme: 'I thought, let the aged speak; let many years teach wisdom' — the assumption that age accumulates wisdom. The NT confirms the honor due to elders (1 Tim 5:17) while also holding that wisdom is a gift of the Spirit, not a product of years (1 Cor 12:8). Both are true; neither is absolute.</p>",
    "8": "<p>A revelation of God: 'but it is the Spirit in a person — the breath of the Almighty — that gives them understanding' — the Spirit as the giver of wisdom, independent of human credentials. The NT's Pentecost theology is the full expression of this: 'I will pour out my Spirit on all flesh, and your sons and daughters shall prophesy' (Acts 2:17). The understanding Elihu describes as the Spirit's gift to individuals becomes, at Pentecost, the Spirit's gift to the whole community.</p>",
    "9": "<p>A revelation of God: 'it is not the great who are always wise, nor the aged who always understand' — the democratization of wisdom through the Spirit. The NT's corroboration: 'God chose what is foolish in the world to shame the wise; God chose what is weak in the world to shame the strong' (1 Cor 1:27). The Spirit bypasses credentials and status.</p>",
    "10": "<p>A theme: 'therefore I say: listen to me; I too will express what I think' — the claim to a hearing on the basis of Spirit-given insight rather than social status. The NT's pattern of prophetic speech is similar: 'we cannot but speak of what we have seen and heard' (Acts 4:20). The compulsion to speak comes from the reality of what has been received, not from earned authority.</p>",
    "11": "<p>A theme: 'I listened carefully to your arguments while you searched for what to say' — the patient attending to all that has been said before adding one's own voice. The NT's wisdom: 'let every person be quick to hear, slow to speak, slow to anger' (Jas 1:19). Elihu embodies the listening before speaking that wisdom requires.</p>",
    "12": "<p>A revelation of God: 'not one of you has refuted Job or answered what he said' — the honest assessment that conventional theology has not provided a real answer. The NT identifies the real answer: the cross and resurrection supply what no theodicy argument can — not an explanation of suffering but the presence of God in suffering and the power of God through it.</p>",
    "13": "<p>A theme: 'do not say, we have found wisdom; let God deal with him' — the warning against deflecting to God as a way of avoiding the hard intellectual work. The NT's parallel: the disciples who asked 'who sinned, this man or his parents?' (John 9:2) were similarly attempting to route the uncomfortable case into a pre-formed theological category. Jesus rejected the deflection and addressed the situation directly.</p>",
    "14": "<p>A theme: 'he has not directed his argument against me, and I will not reply to him with your kind of arguments' — Elihu's commitment to engage afresh rather than repeat the failed approach. The NT's pattern: Jesus taught 'as one who had authority, and not as their scribes' (Matt 7:29) — not reprising the existing framework but speaking from a different ground entirely.</p>",
    "15": "<p>A revelation of God: 'they are astonished; they say nothing more; words have left them' — the exhaustion of human wisdom before the problem of innocent suffering. The NT's response is not a better argument but a person: 'in these last days he has spoken to us by his Son' (Heb 1:2). When words have left human wisdom, God speaks his final word in flesh.</p>",
    "16": "<p>A theme: 'I waited, but they did not speak; they stood there and answered no more' — the silence that precedes the new voice. In the NT, silence precedes the new word: the silence of Zechariah before the angel (Luke 1:20), the silence of Jesus before Pilate (Matt 27:14), and ultimately the silence of the tomb before Easter morning. Silence is not the end; it is the space before the decisive speech.</p>",
    "17": "<p>A theme: 'I too will give my answer; I too will state what I think' — the moment of prophetic declaration. The NT holds that Spirit-impelled speech is not merely opinion-sharing: 'the Holy Spirit will teach you in that very hour what you ought to say' (Luke 12:12). Elihu's 'what I think' is not mere opinion; he believes he speaks by the Spirit (32:8).</p>",
    "18": "<p>A revelation of God: 'I am full of words; the Spirit within me urges me on' — the prophetic compulsion to speak. The NT's parallel: Jeremiah's 'there is in my heart as it were a burning fire shut up in my bones' (Jer 20:9); the disciples who 'cannot but speak' (Acts 4:20). The Spirit's fullness presses outward; the contained word demands release.</p>",
    "19": "<p>A shadow: 'my belly is like wine with no outlet — like new wineskins about to burst' — the pressure of uncontained speech. The NT's new wine imagery: 'no one puts new wine into old wineskins. If he does, the wine will burst the skins' (Mark 2:22). The new teaching that Jesus brings has exactly this character — it cannot be contained in the old forms. Elihu's image anticipates the NT's description of the gospel's pressure on old structures.</p>",
    "20": "<p>A theme: 'I will speak and find relief; I will open my lips and answer' — the therapeutic necessity of faithful speech. The NT's parallel is testimony: 'for with the heart one believes and is justified, and with the mouth one confesses and is saved' (Rom 10:10). Speaking what one has received is not just transmission but a form of receiving it more fully.</p>",
    "21": "<p>A revelation of God: 'I will show partiality to no one, nor will I flatter anyone' — the impartiality that the Spirit-given voice must maintain. The NT grounds divine impartiality in God's own character: 'God shows no partiality' (Rom 2:11; Acts 10:34). The judge of all is impartial; the witness who speaks for him must be as well.</p>",
    "22": "<p>A revelation of God: 'for I do not know how to flatter; if I did, my Maker would soon remove me' — the accountability of the prophetic witness before his Maker. The NT's equivalent: 'we must all appear before the judgment seat of Christ, so that each one may receive what is due for what he has done in the body' (2 Cor 5:10). The one who flatters rather than speaks truth has disqualified himself before his Maker.</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'job')
    merge_comm(existing, JOB)
    save_comm('mkt-christ', 'job', existing)
    total = sum(len(v) for v in JOB.values())
    print(f'job mkt-christ: wrote {total} verse entries across ch 30-32')

if __name__ == '__main__':
    main()
